-- Session 2: humanize task assignees and HR assignees / creators for AI evidence (read surfaces only).

create or replace function public.get_tasks_ai_operational_evidence(
  p_project_id uuid,
  p_task_limit integer default 25,
  p_offset integer default 0
)
returns jsonb
language plpgsql
stable
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_limit integer := least(greatest(coalesce(p_task_limit, 25), 1), 50);
  v_offset integer := greatest(coalesce(p_offset, 0), 0);
  v_ai text;
  v_tasks jsonb;
begin
  if v_uid is null then
    return jsonb_build_object('tasks', '[]'::jsonb);
  end if;

  if not public.can_access_project(p_project_id) then
    return jsonb_build_object('tasks', '[]'::jsonb);
  end if;

  v_ai := public.effective_ai_access_for_profile(p_project_id);
  if v_ai is null or v_ai = 'none' then
    return jsonb_build_object('tasks', '[]'::jsonb);
  end if;

  select coalesce(
    (
      with task_rows as (
        select
          t.id,
          t.title,
          t.status,
          t.stage_id,
          ps.title as stage_title,
          t.assignee_profile_id,
          left(coalesce(ap.full_name, ''), 120) as assignee_display_name,
          t.due_at,
          t.completed_at,
          t.updated_at
        from public.tasks t
        join public.project_stages ps
          on ps.id = t.stage_id
        left join public.profiles ap
          on ap.id = t.assignee_profile_id
        where t.project_id = p_project_id
        order by t.updated_at desc, t.id desc
        offset v_offset
        limit v_limit
      )
      select jsonb_agg(
        jsonb_build_object(
          'task_id', tr.id,
          'title', tr.title,
          'status', tr.status,
          'stage_id', tr.stage_id,
          'stage_title', tr.stage_title,
          'assignee_profile_id', tr.assignee_profile_id,
          'assignee_display_name', tr.assignee_display_name,
          'due_at', tr.due_at,
          'completed_at', tr.completed_at,
          'updated_at', tr.updated_at,
          'checklist_items', coalesce(cl.items, '[]'::jsonb),
          'recent_comments', coalesce(cm.items, '[]'::jsonb)
        )
        order by tr.updated_at desc, tr.id desc
      )
      from task_rows tr
      left join lateral (
        select coalesce(
          jsonb_agg(
            jsonb_build_object(
              'title', ci.title,
              'is_done', ci.is_done
            )
            order by ci.sort_order
          ),
          '[]'::jsonb
        ) as items
        from (
          select tci.title, tci.is_done, tci.sort_order
          from public.task_checklist_items tci
          where tci.task_id = tr.id
          order by tci.sort_order
          limit 8
        ) ci
      ) cl on true
      left join lateral (
        select coalesce(
          jsonb_agg(
            jsonb_build_object(
              'created_at', c.created_at,
              'body', left(c.body, 400)
            )
            order by c.created_at desc
          ),
          '[]'::jsonb
        ) as items
        from (
          select tc.created_at, tc.body
          from public.task_comments tc
          where tc.task_id = tr.id
          order by tc.created_at desc
          limit 3
        ) c
      ) cm on true
    ),
    '[]'::jsonb
  )
  into v_tasks;

  return jsonb_build_object('tasks', coalesce(v_tasks, '[]'::jsonb));
end;
$$;

revoke all on function public.get_tasks_ai_operational_evidence(uuid, integer, integer) from public;
grant execute on function public.get_tasks_ai_operational_evidence(uuid, integer, integer) to authenticated;

create or replace function public.get_hr_operational_summary(
  p_project_id uuid,
  p_limit integer default 200,
  p_offset integer default 0
)
returns jsonb
language plpgsql
stable
security definer
set search_path = public
as $$
declare
  v_limit integer := least(greatest(coalesce(p_limit, 200), 1), 500);
  v_offset integer := greatest(coalesce(p_offset, 0), 0);
  v_allowed boolean;
  v_finance text;
  v_hr_items jsonb := '[]'::jsonb;
begin
  v_allowed := public.can_access_project(p_project_id);

  if not v_allowed then
    return jsonb_build_object(
      'hr_items', '[]'::jsonb
    );
  end if;

  if not public.can_access_hr_domain(p_project_id) then
    return jsonb_build_object(
      'hr_items', '[]'::jsonb
    );
  end if;

  v_finance := public.effective_finance_visibility(p_project_id);

  select coalesce(
    jsonb_agg(
      jsonb_build_object(
        'hr_item_id', rows.hr_item_id,
        'project_id', rows.project_id,
        'project_stage_id', rows.project_stage_id,
        'estimate_work_id', rows.estimate_work_id,
        'estimate_resource_line_id', rows.estimate_resource_line_id,
        'estimate_resource_line_resource_type', rows.estimate_resource_line_resource_type,
        'task_id', rows.task_id,
        'title', rows.title,
        'description', rows.description,
        'compensation_type', rows.compensation_type,
        'planned_cost_cents',
          case when v_finance = 'detail' then rows.planned_cost_cents else null end,
        'actual_cost_cents',
          case when v_finance = 'detail' then rows.actual_cost_cents else null end,
        'status', rows.status,
        'start_at', rows.start_at,
        'end_at', rows.end_at,
        'created_by', rows.created_by,
        'created_by_display_name', rows.created_by_display_name,
        'created_at', rows.created_at,
        'updated_at', rows.updated_at,
        'assignees', rows.assignees
      )
      order by rows.updated_at desc, rows.hr_item_id
    ),
    '[]'::jsonb
  )
  into v_hr_items
  from (
    select
      hi.id as hr_item_id,
      hi.project_id,
      hi.project_stage_id,
      hi.estimate_work_id,
      hi.estimate_resource_line_id,
      erl.resource_type as estimate_resource_line_resource_type,
      hi.task_id,
      hi.title,
      hi.description,
      hi.compensation_type,
      hi.planned_cost_cents,
      hi.actual_cost_cents,
      hi.status,
      hi.start_at,
      hi.end_at,
      hi.created_by,
      left(coalesce(creator.full_name, ''), 120) as created_by_display_name,
      hi.created_at,
      hi.updated_at,
      (
        select coalesce(jsonb_agg(
          jsonb_build_object(
            'profile_id', hia.profile_id,
            'role_label', hia.role_label,
            'display_name', left(coalesce(ap.full_name, ''), 120)
          )
          order by hia.profile_id
        ), '[]'::jsonb)
        from public.hr_item_assignees hia
        left join public.profiles ap
          on ap.id = hia.profile_id
        where hia.hr_item_id = hi.id
      ) as assignees
    from public.hr_items hi
    left join public.estimate_resource_lines erl
      on erl.id = hi.estimate_resource_line_id
    left join public.profiles creator
      on creator.id = hi.created_by
    where hi.project_id = p_project_id
    order by hi.updated_at desc, hi.id
    offset v_offset
    limit v_limit
  ) rows;

  return jsonb_build_object(
    'hr_items', v_hr_items
  );
end;
$$;

revoke all on function public.get_hr_operational_summary(uuid, integer, integer) from public;
grant execute on function public.get_hr_operational_summary(uuid, integer, integer) to authenticated;
